"use client";

import Link from "next/link";
import { useParams } from "next/navigation";
import { useEffect, useMemo, useState } from "react";
import {
  ArrowLeft,
  ClipboardList,
  Database,
  ShieldCheck,
} from "lucide-react";

import ClinicalShell from "@/components/clinical/ClinicalShell";
import ClinicalRecordCard from "@/components/clinical/ClinicalRecordCard";
import { DashboardCard } from "@/components/clinical/EnterpriseDashboard";
import { getHrmsModuleConfig } from "@/lib/clinical/hrms-core";

type Row = Record<string, unknown>;

type ModulePayload = {
  module?: {
    key: string;
    label: string;
    table: string;
    category: string;
    description: string;
    primaryColumns: string[];
  };
  metrics?: Record<string, string | number | null>;
  rows?: Row[];
  error?: string;
};

export default function ClinicalHrmsModulePage() {
  const params = useParams();
  const key = String(params.module || "");
  const fallbackConfig = useMemo(
    () => getHrmsModuleConfig(key),
    [key]
  );
  const [data, setData] =
    useState<ModulePayload | null>(null);

  useEffect(() => {
    const timer =
      window.setTimeout(async () => {
        const response = await fetch(
          `/api/clinical/hrms/${key}`
        );

        if (response.ok) {
          setData(await response.json());
        } else {
          setData({
            error:
              "Unable to load this HRMS module.",
          });
        }
      }, 0);

    return () =>
      window.clearTimeout(timer);
  }, [key]);

  const moduleConfig =
    data?.module || fallbackConfig;
  const rows = data?.rows || [];
  const metrics = data?.metrics || {};

  return (
    <ClinicalShell>
      <div className="space-y-6 p-4">
        <Link
          href="/clinical-services/hrms"
          className="inline-flex items-center gap-2 rounded-[8px] border border-slate-200 bg-white px-4 py-2 text-sm font-black text-slate-950 shadow-sm"
        >
          <ArrowLeft size={16} />
          HRMS Command Center
        </Link>

        <section className="tt-clinical-dark-hero rounded-[8px] border border-[#D4AF37]/50 bg-[#0B1F3A] p-7 text-white shadow-sm">
          <p className="text-xs font-black uppercase tracking-[0.14em] text-[#D4AF37]">
            {moduleConfig?.category ||
              "HRMS"}
          </p>
          <h1 className="mt-2 text-4xl font-black">
            {moduleConfig?.label ||
              "HRMS Module"}
          </h1>
          <p className="mt-3 max-w-4xl text-sm font-semibold leading-6 text-slate-100">
            {moduleConfig?.description ||
              data?.error ||
              "Clinical workforce module."}
          </p>
        </section>

        <section className="grid gap-4 md:grid-cols-3">
          <DashboardCard
            title="Records"
            value={metrics.total}
            icon={Database}
            drillDownUrl={`/clinical-services/hrms/${key}`}
            caption="Open HRMS records"
          />
          <DashboardCard
            title="Today"
            value={metrics.today}
            icon={ClipboardList}
            drillDownUrl={`/clinical-services/hrms/${key}?date=today`}
            caption="Today's workforce records"
          />
          <DashboardCard
            title="Tenant Scope"
            value="Isolated"
            icon={ShieldCheck}
            drillDownUrl="/clinical-services/security"
            caption="Security context"
          />
        </section>

        <section className="rounded-[8px] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="flex flex-col gap-3 sm:flex-row sm:items-end sm:justify-between">
            <div>
              <p className="text-xs font-black uppercase text-[#8a6500]">
                Source Table
              </p>
              <h2 className="mt-1 break-words text-2xl font-black text-slate-950">
                {moduleConfig?.table || "-"}
              </h2>
            </div>
            <p className="rounded-[8px] border border-[#D4AF37]/40 bg-[#fff9e8] px-4 py-2 text-xs font-black uppercase text-[#8a6500]">
              Tenant + Hospital + Branch isolated
            </p>
          </div>

          <div className="mt-5 grid gap-3 md:grid-cols-2 xl:grid-cols-3">
            {(moduleConfig?.primaryColumns || []).map(
              (column) => (
                <div
                  key={column}
                  className="rounded-[8px] border border-slate-200 bg-slate-50 p-3"
                >
                  <p className="text-xs font-black uppercase text-slate-500">
                    Field
                  </p>
                  <p className="mt-1 break-words text-sm font-black text-slate-950">
                    {column}
                  </p>
                </div>
              )
            )}
          </div>
        </section>

        <section className="rounded-[8px] border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-2xl font-black">
            Records
          </h2>

          {rows.length ? (
            <div className="mt-4 grid gap-3">
              {rows.map((row, index) => (
                <ClinicalRecordCard
                  key={`${moduleConfig?.key}-${index}`}
                  href={`/clinical-services/hrms/${key}/${row.id || index}`}
                  eyebrow={`ID ${String(row.id || index)}`}
                  title={recordTitle(row, moduleConfig?.label || "HRMS Record")}
                  description={`${moduleConfig?.category || "HRMS"} record`}
                  status={String(row.status || row.employee_status || row.approval_status || "-")}
                  editHref={`/clinical-services/hrms/${key}?record=${row.id || index}&mode=edit`}
                  auditHref={`/clinical-services/hrms/${key}/${row.id || index}#audit`}
                  historyHref={`/clinical-services/hrms/${key}/${row.id || index}#history`}
                >
                  <RecordCard
                    row={row}
                    columns={
                      moduleConfig?.primaryColumns ||
                      []
                    }
                  />
                </ClinicalRecordCard>
              ))}
            </div>
          ) : (
            <div className="mt-4 rounded-[8px] border border-slate-200 bg-slate-50 p-4 text-sm font-bold text-slate-600">
              No records found for this
              HRMS module yet.
            </div>
          )}
        </section>
      </div>
    </ClinicalShell>
  );
}

function recordTitle(row: Row, fallback: string) {
  const firstColumn =
    Object.entries(row).find(
      ([key, value]) =>
        key.endsWith("_name") &&
        value !== null &&
        value !== undefined
    )?.[1] ??
    row.employee_number ??
    row.employee_id ??
    row.course_name ??
    row.shift_name ??
    row.id;

  return String(firstColumn || fallback);
}

function RecordCard({
  row,
  columns,
}: {
  row: Row;
  columns: string[];
}) {
  const visibleColumns =
    columns.length
      ? columns
      : Object.keys(row).slice(0, 6);

  return (
    <article className="rounded-[8px] border border-slate-200 bg-slate-50 p-4 transition hover:border-[#D4AF37] hover:bg-white hover:shadow-md">
      <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-3">
        {visibleColumns.map((column) => (
          <div
            key={column}
            className="min-w-0"
          >
            <p className="text-[11px] font-black uppercase text-slate-500">
              {column}
            </p>
            <p className="mt-1 break-words text-sm font-bold text-slate-950">
              {formatValue(row[column])}
            </p>
          </div>
        ))}
      </div>
    </article>
  );
}

function formatValue(value: unknown) {
  if (value === null || value === undefined) {
    return "-";
  }

  if (
    typeof value === "object"
  ) {
    return JSON.stringify(value);
  }

  return String(value);
}
